SELECT
  e.student_id,
  cs.course_id,
  cs.semester_id,
  g.id,
  g.status,
  CASE
    WHEN g.status = 'retake' THEN 'Demo data: student is eligible for retake exam'
    ELSE 'Demo data: student should repeat the course'
  END AS note
FROM grades g
JOIN enrollments e ON e.id = g.enrollment_id
JOIN class_sections cs ON cs.id = e.class_section_id
WHERE g.status IN ('retake', 'repeat')
  AND cs.section_code IN ('BAS1153-01', 'BAS1153-02', 'BAS1153-03', 'BAS1160-01', 'BAS1160-02', 'BAS1160-03', 'INT1313-01', 'INT1313-02', 'INT1313-03', 'INT13162-01', 'INT13162-02', 'INT13162-03', 'INT1319-01', 'INT1319-02', 'INT1319-03', 'INT1332-01', 'INT1332-02', 'INT1332-03', 'INT1336-01', 'INT1336-02', 'INT1336-03', 'INT1303-01', 'INT1303-02', 'INT1303-03', 'INT13187-01', 'INT13187-02', 'INT13187-03', 'INT1340-01', 'INT1340-02', 'INT1340-03', 'INT1341-01', 'INT1341-02', 'INT1341-03', 'INT14148-01', 'INT14148-02', 'INT14148-03', 'INT1434-3-01', 'INT1434-3-02', 'INT1434-3-03', 'SKD1103-01', 'SKD1103-02', 'SKD1103-03');

